```
rs2::context rs_ctx;
const std::string platform_camera_name = "Platform Camera";
i = 0;
for (auto&& dev : rs_ctx.query_devices()) 
{
    if (dev.get_info(RS2_CAMERA_INFO_NAME) == platform_camera_name) continue;

    rs2::pipeline pipe;
    rs2::config cfg;

